VALUES
  ('locality-d0d1b9a2-moex-00534', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-194ec0d9', 'sub-locality-d0d1b9a2-06', NULL, 'single_choice', '甲公司6月份有關製造費用之資料如下： 已發生實際製造費用 $69,000 分攤至在製品的製造費用 $76,000 該公司將製造費用結入銷貨成本。銷貨成本帳戶在製造費用結入前之餘額為$255,000。下列 敘述何者正確？', '["製造費用少分攤$7,000，銷貨成本在製造費用結入後之餘額為$248,000", "製造費用多分攤$7,000，銷貨成本在製造費用結入後之餘額為$248,000", "製造費用少分攤$7,000，銷貨成本在製造費用結入後之餘額為$262,000", "製造費用多分攤$7,000，銷貨成本在製造費用結入後之餘額為$262,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:10+00:00", "source_pdf_sha1": "5600a718a2d5", "answer_pdf_sha1": "18bfd041b04c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00535', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-194ec0d9', 'sub-locality-d0d1b9a2-06', NULL, 'single_choice', '甲公司10月份資料如下： 在製品 製成品 銷貨成本 合計 直接材料 $3,900 $16,800 $112,840 $133,540 直接人工 $1,310 $12,000 $80,600 $93,910 已分攤製造費用 $1,650 $7,150 $46,200 $55,000 合計 $6,860 $35,950 $239,640 $282,450 假設無期初存貨，當月份製造費用少分攤$2,000。公司以分攤到在製品、製成品與銷貨成本三 個帳戶之製造費用金額為依據，分配多分攤或少分攤製造費用。試問銷貨成本帳戶在分配多 分攤或少分攤製造費用後餘額為何？', '["$241,320", "$237,960", "$241,640", "$237,640"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:10+00:00", "source_pdf_sha1": "5600a718a2d5", "answer_pdf_sha1": "18bfd041b04c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00536', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-194ec0d9', 'sub-locality-d0d1b9a2-06', NULL, 'single_choice', 'B公司每單位產品需投入原料2單位，原料每單位為$5，產品的損壞率為10%，原料的殘料 率為20%，若公司通過檢驗的產品為90單位，試計算所需要的原料成本為何？', '["$900", "$1,000", "$1,125", "$1,250"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:10+00:00", "source_pdf_sha1": "5600a718a2d5", "answer_pdf_sha1": "18bfd041b04c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00537', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-194ec0d9', 'sub-locality-d0d1b9a2-06', NULL, 'single_choice', '甲公司標準工資率每小時$5，X8年3月份發生人工效率有利差異$250，工資率不利差異$200， 實際發生直接人工小時數2,000小時，試問每小時實際工資率為何？', '["$4.8", "$4.9", "$5.1", "$5.2"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:10+00:00", "source_pdf_sha1": "5600a718a2d5", "answer_pdf_sha1": "18bfd041b04c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00538', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-194ec0d9', 'sub-locality-d0d1b9a2-06', NULL, 'single_choice', '某公司販售每個定價$500的商品，每單位的直接材料成本為$185，每單位需要3小時的直接 人工，工資率為每小時$25，製造費用全部為固定，預定製造販售2,000個商品，若以人工小 時為基礎，每小時分攤率為$40，該公司需販售多少個商品才能損益兩平？', '["276", "334", "828", "1,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:10+00:00", "source_pdf_sha1": "5600a718a2d5", "answer_pdf_sha1": "18bfd041b04c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00539', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-194ec0d9', 'sub-locality-d0d1b9a2-06', NULL, 'single_choice', '某公司去年邊際貢獻率為40%，今年銷貨收入為$960,000比去年增加20%，今年的固定成本 與去年相同均為$150,000，如果公司希望今年的淨利比去年增加$16,000，則今年的邊際貢獻 率應為何？', '["30%", "35%", "40%", "45%"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:10+00:00", "source_pdf_sha1": "5600a718a2d5", "answer_pdf_sha1": "18bfd041b04c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00540', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-194ec0d9', 'sub-locality-d0d1b9a2-06', NULL, 'single_choice', '下列有關「變動成本法」之敘述，何者錯誤？', '["變動成本法忽略長期利潤目標", "變動成本法便於成本分析及控制", "變動成本法便於管理與考核", "變動成本法降低企業舉債能力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:10+00:00", "source_pdf_sha1": "5600a718a2d5", "answer_pdf_sha1": "18bfd041b04c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00541', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-194ec0d9', 'sub-locality-d0d1b9a2-06', NULL, 'single_choice', '甲公司生產A、B二種產品，都是使用人工生產為主，直接人工每小時工資率為$45，並以直 接人工小時做為製造費用之分攤基礎。製造費用成本函數為：全年製造費用總數 =$600,000+$20×直接人工時數 X1年5月份相關資料如下：產品A、B的生產預算分別為750單位、400單位，產品A、B 每一單位直接人工時數則分別為4小時、6小時。下列敘述何者錯誤？', '["X1年5月份，產品A的直接人工成本預算為$135,000", "X1年5月份，產品B的直接人工成本預算為$108,000", "X1年5月份，甲公司製造費用預算為$708,000", "X1年5月份，甲公司製造費用預算為$158,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:10+00:00", "source_pdf_sha1": "5600a718a2d5", "answer_pdf_sha1": "18bfd041b04c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00542', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-194ec0d9', 'sub-locality-d0d1b9a2-06', NULL, 'single_choice', '甲公司產銷X產品。目前產銷量為15,600單位，營收$686,400，變動製造成本$374,400，固 定製造費用$156,000，變動銷管費用$68,640，固定銷管費用$45,760。 今有乙公司向甲公司提出以單價$32訂購3,900單位X產品。甲公司總經理認為這筆生意有利可 圖，因為公司尚有剩餘產能，而且這筆生意可節省變動銷管費用；但營運長則認為X產品單位 製造成本已達$34，高於乙公司提出的買價。若接受此特殊訂單對甲公司的淨利影響為何？', '["增加$7,800", "減少$7,800", "增加$31,200", "減少$31,200"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:10+00:00", "source_pdf_sha1": "5600a718a2d5", "answer_pdf_sha1": "18bfd041b04c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00543', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-194ec0d9', 'sub-locality-d0d1b9a2-06', NULL, 'single_choice', '甲公司擬購置新機器設備，成本$2,000,000，估計耐用年限10年，無殘值，採直線法折舊。 新機器設備每年需增加現金支出$500,000。若該機器設備原始投資額的會計報酬率為 15%， 則新機器設備每年為公司增加的銷貨收入為何？', '["$300,000", "$500,000", "$800,000", "$1,000,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:10+00:00", "source_pdf_sha1": "5600a718a2d5", "answer_pdf_sha1": "18bfd041b04c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL)
